arguments.argument:
if sprite_index=sFullHealthPickup
{
  setCollisionBounds(-7,-7,7,7)
  yVel=0
  yVelLimit=4
}
else if sprite_index=sCVChicken
{
  yVel=0
}
else if sprite_index=sMMHealthPickup
{
  setCollisionBounds(-8,-6,8,6)
  image_speed=0.2
}
else if sprite_index=sMetroidHealthPickup
{
  image_speed=0.33
}
